import{_ as s,d,e as n,f as a,g as i,w as r,i as t,t as l,k as p,v as u}from"./index-BX0C5YrI.js";const c={class:"legal"},v={class:"page-top"},h={class:"muted footer-links"},m="July 14, 2026",y={__name:"PrivacyPage",setup(g){return(w,e)=>{const o=u("router-link");return d(),n("div",c,[a("div",v,[i(o,{to:"/",class:"home-link"},{default:r(()=>[...e[0]||(e[0]=[t("‹ Home",-1)])]),_:1})]),e[4]||(e[4]=a("h1",null,"Privacy policy",-1)),a("p",{class:"muted updated"},"Last updated "+l(m)),e[5]||(e[5]=p('<p data-v-4ed5202e> SaunaSpeak is a web app for learning spoken Finnish, operated as an independent product from Finland&#39;s neighborhood (EU). This page explains what we store, why, and what you can do about it - in plain language, because nobody learns Finnish to read legalese. </p><h2 data-v-4ed5202e>What we store</h2><ul data-v-4ed5202e><li data-v-4ed5202e><b data-v-4ed5202e>Account:</b> your name, email address and a hashed password (we can never read the password itself).</li><li data-v-4ed5202e><b data-v-4ed5202e>Learning data:</b> which sentences and words you&#39;ve studied, your self-grades, review schedule, streak, XP, checkpoints, preferences (goal, daily time, audio speed) and timezone. This is the product - spaced repetition can&#39;t work without it.</li><li data-v-4ed5202e><b data-v-4ed5202e>Chat messages:</b> what you write to Väinö or a scenario character is sent to an AI provider to generate the reply (see below). Practice-attempt corrections are cached so identical mistakes get instant answers.</li><li data-v-4ed5202e><b data-v-4ed5202e>Billing (Löyly+ only):</b> payments run entirely through <a href="https://stripe.com/privacy" rel="noopener" target="_blank" data-v-4ed5202e>Stripe</a>. We store your Stripe customer and subscription IDs and your subscription status - never your card number.</li></ul><h2 data-v-4ed5202e>What we deliberately don&#39;t do</h2><ul data-v-4ed5202e><li data-v-4ed5202e>No advertising, no selling or sharing data with data brokers - ever.</li><li data-v-4ed5202e>No tracking cookies. Analytics run on <a href="https://umami.is/privacy" rel="noopener" target="_blank" data-v-4ed5202e>Umami</a>, a cookieless, EU-hosted service that counts page views without identifying you.</li><li data-v-4ed5202e>No social-media pixels, no fingerprinting.</li></ul><h2 data-v-4ed5202e>Processors we rely on</h2><p data-v-4ed5202e> A few services process data on our behalf, only to make features work: our hosting provider (servers and database), Stripe (payments), an email delivery provider (verification, password-reset and optional review-reminder mails), an AI provider (Anthropic, Google or OpenRouter - chat replies and practice corrections; messages are sent for processing, not used by us to train anything), and a speech-synthesis provider (Microsoft or Google) for generating Finnish audio. </p><h2 data-v-4ed5202e>Emails</h2><p data-v-4ed5202e> We send account emails (verification, password reset) and - if you keep the toggle on in your profile - a daily reminder when reviews are due. The reminder can be switched off in your profile at any time. </p><h2 data-v-4ed5202e>Your rights</h2><ul data-v-4ed5202e><li data-v-4ed5202e><b data-v-4ed5202e>Export:</b> download everything we hold about you as JSON from your profile (&quot;Download my data&quot;).</li><li data-v-4ed5202e><b data-v-4ed5202e>Deletion:</b> delete your account from your profile - it removes your account, progress, word bank and review history immediately, and cancels any active subscription. This is irreversible.</li><li data-v-4ed5202e><b data-v-4ed5202e>Correction &amp; access:</b> for anything else (GDPR articles 15-21), email us and we&#39;ll sort it out.</li></ul><h2 data-v-4ed5202e>Retention</h2><p data-v-4ed5202e> We keep your data for as long as your account exists. Delete the account and it&#39;s gone from the live database immediately; encrypted backups rotate out within 30 days. </p><h2 data-v-4ed5202e>Contact</h2><p data-v-4ed5202e> Questions, requests, complaints: <a href="mailto:mail@saunaspeak.com" data-v-4ed5202e>mail@saunaspeak.com</a>. You also have the right to lodge a complaint with your local data-protection authority. </p>',15)),a("p",h,[i(o,{to:"/terms"},{default:r(()=>[...e[1]||(e[1]=[t("Terms of service",-1)])]),_:1}),e[3]||(e[3]=t(" · ",-1)),i(o,{to:"/"},{default:r(()=>[...e[2]||(e[2]=[t("Home",-1)])]),_:1})])])}}},b=s(y,[["__scopeId","data-v-4ed5202e"]]);export{b as default};
